import os
import re
import shutil
import subprocess
import sys
import tempfile
from pathlib import Path

_REPO = Path(__file__).resolve().parents[3]

# The bare-/root env-default class named in AC-WS1-9 (each verified by Read).
_BARE_ROOT_SITES = [
    "hooks/merge.sh", "hooks/posttool-overnight-trace.py",
    "hooks/lib/bash_write_targets.py", "hooks/lib/closeout.py",
    "hooks/lib/specialist_yield.py", "scripts/break-overnight-lock.py",
    "hooks/push.sh", "hooks/prompt-workflow.py",
    "scripts/apply-permissions.sh", "scripts/resolve-close-report.sh",
]

# Boundary-aware author-home pattern (AC-WS3-4 REV4): a bare /root at any
# non-path boundary OR any /root/... prefix, anchored against word chars.
_AUTHOR_ROOT = re.compile(r"(?<![\w./])/root(?:/|(?=$|[^\w./-]))")


def _strip_comment(line: str, ext: str) -> str:
    """Return the executable portion of a line (best-effort comment stripping)."""
    if ext in (".sh",):
        # Drop a leading-hash comment line; trim a trailing ' # ...' comment.
        if line.lstrip().startswith("#"):
            return ""
        return re.split(r"\s#", line, maxsplit=1)[0]
    if ext == ".py":
        if line.lstrip().startswith("#"):
            return ""
        return re.split(r"\s#", line, maxsplit=1)[0]
    return line


def _scan_bare_root_defaults():
    """Yield (file, lineno, text) for any EXECUTABLE bare-/root author default
    left in the named sites. Docstrings/comments are not perfectly excluded for
    .py, so we additionally require the line to look like an env-DEFAULT use
    (`:-/root`, `,'/root'`, `,"/root"`, `Path('/root')`, `echo /root`,
    `echo "/root"`)."""
    default_use = re.compile(
        r""":-\s*/root\b"""              # ${VAR:-/root}
        r"""|,\s*['"]/root['"]"""        # get(KEY, '/root')
        r"""|Path\(\s*['"]/root['"]"""   # Path('/root')
        r"""|echo\s+["']?/root\b"""      # || echo /root / echo "/root"
    )
    hits = []
    for rel in _BARE_ROOT_SITES:
        p = _REPO / rel
        ext = p.suffix
        for i, raw in enumerate(p.read_text().splitlines(), start=1):
            code = _strip_comment(raw, ext)
            if not code:
                continue
            if _AUTHOR_ROOT.search(code) and default_use.search(code):
                hits.append((rel, i, raw.strip()))
    return hits


def _make_clone() -> Path:
    """Synthetic harness home (basename dot-claude) with the WS1 resolvers +
    the two fixed shell scripts, for behavioral default-resolution probes."""
    tmp_home = Path(tempfile.mkdtemp(prefix="ws1-bareroot-"))
    clone = tmp_home / "dot-claude"
    (clone / "hooks" / "lib").mkdir(parents=True)
    (clone / "policies").mkdir()
    (clone / "scripts").mkdir()
    (clone / "settings.json").write_text("{}\n")
    for rel in ("hooks/lib/claude_home.py", "hooks/lib/claude_home.sh",
                "scripts/apply-permissions.sh", "scripts/resolve-close-report.sh"):
        shutil.copy2(_REPO / rel, clone / rel)
    return clone


def _env_no_home(clone: Path) -> dict:
    # CLAUDE_PROJECT_DIR + HOME UNSET; only PATH/LANG present. The resolver must
    # fall back to the structural walk root, never the author literal /root.
    return {"PATH": os.environ.get("PATH", "/usr/bin:/bin"), "LANG": "C"}


def test_AC_WS1_9():
    r"""
    GIVEN: The bare-/root env-default class in active runtime code (verified by Read): merge.sh:109 PROJ="${CLAUDE_PROJECT_DIR:-/root}"; posttool-overnight-trace.py:63 os.environ.get('CLAUDE_PROJECT_DIR','/root'); hooks/lib/bash_write_targets.py:163 os.environ.get('HOME','/root'); hooks/lib/closeout.py:44; hooks/lib/specialist_yield.py:62; scripts/break-overnight-lock.py:24; AND the bare-/root git-toplevel fallbacks codex #3 surfaced: hooks/push.sh:93/192 (|| echo /root), hooks/prompt-workflow.py:67 (return Path('/root')), scripts/apply-permissions.sh:10 (|| echo /root), scripts/resolve-close-report.sh:18 (CONTROL_ROOT:-/root). The prior grep pattern /root/\.claude|/root/bin|/dev/shm did NOT match a bare /root, so these were absent from the inventory.
    WHEN:  any of these runs on a fresh non-root clone with CLAUDE_PROJECT_DIR / HOME unset
    THEN:  the default is the resolved harness home / project dir via the WS1 resolver (or $HOME / git-toplevel as appropriate), NOT the author's literal /root; where the value is security-relevant the absence path fails closed
    """
    # (1) STATIC: no EXECUTABLE bare-/root author-home default remains in any of
    # the named WS1 sites (the whole point of the AC-WS1-9 migration).
    hits = _scan_bare_root_defaults()
    assert hits == [], (
        "bare-/root author-home default(s) still present in WS1 sites:\n"
        + "\n".join(f"  {f}:{ln}: {txt}" for f, ln, txt in hits))

    clone = _make_clone()
    walk_root = str(clone.resolve())
    env = _env_no_home(clone)

    # (2) BEHAVIORAL: claude_home.project_dir() with HOME + CLAUDE_PROJECT_DIR
    # UNSET resolves to the walk root, NEVER the literal /root.
    proj = subprocess.run(
        [sys.executable, "-c",
         "import sys; sys.path.insert(0, sys.argv[1]); import claude_home; "
         "print(claude_home.project_dir())",
         str(clone / "hooks" / "lib")],
        env=env, capture_output=True, text=True, cwd=str(clone),
    )
    assert proj.returncode == 0, f"project_dir probe failed: {proj.stderr!r}"
    assert _AUTHOR_ROOT.search(proj.stdout.strip()) is None, (
        f"project_dir() defaulted to an author /root path: {proj.stdout.strip()!r}")
    assert proj.stdout.strip() == walk_root, (
        f"project_dir() should resolve to the walk root; got {proj.stdout.strip()!r}")

    # (3) BEHAVIORAL: the shell git-toplevel fallback (git fails because the clone
    # is not a repo) resolves to the harness home, never /root — the exact pattern
    # apply-permissions.sh:10 now uses.
    fb = subprocess.run(
        ["bash", "-c",
         f'source "{clone}/hooks/lib/claude_home.sh"; '
         'echo "$(git rev-parse --show-toplevel 2>/dev/null || claude_home_resolve || echo "$HOME")"'],
        env=env, capture_output=True, text=True, cwd=str(clone),
    )
    assert _AUTHOR_ROOT.search(fb.stdout.strip()) is None, (
        f"shell git-toplevel fallback defaulted to /root: {fb.stdout.strip()!r}")
    assert fb.stdout.strip() == walk_root, (
        f"shell fallback should be the resolved home; got {fb.stdout.strip()!r}")

    # (4) BEHAVIORAL: resolve-close-report.sh fallback path (no candidate exists)
    # is rooted at the resolved home's CONTROL_ROOT, NEVER /root.
    rcr = subprocess.run(
        ["bash", str(clone / "scripts" / "resolve-close-report.sh"), "no-such-task-id"],
        env=env, capture_output=True, text=True, cwd=str(clone),
    )
    assert rcr.returncode == 1, f"expected exit 1 (no candidate); got {rcr.returncode} stderr={rcr.stderr!r}"
    assert _AUTHOR_ROOT.search(rcr.stdout.strip()) is None, (
        f"resolve-close-report.sh fallback defaulted to /root: {rcr.stdout.strip()!r}")
    assert rcr.stdout.strip().startswith(walk_root), (
        f"resolve-close-report.sh fallback should be under the resolved home; got {rcr.stdout.strip()!r}")
